# Minimal output error correction pipeline in Python
import json
import re

def strip_markdown_fences(raw: str) -> str:
    """Layer 1: remove ```json ... ``` wrappers that LLMs often emit."""
    pattern = r"```(?:json)?\s*([\s\S]*?)```"
    match = re.search(pattern, raw.strip())
    if match:
        return match.group(1).strip()
    return raw.strip()

def parse_with_repair(raw: str) -> dict | None:
    """Try to parse JSON; on failure attempt light repairs."""
    text = strip_markdown_fences(raw)
    try:
        return json.loads(text)
    except json.JSONDecodeError:
        # Attempt: replace single quotes with double quotes (common LLM habit)
        repaired = text.replace("'", "\"")
        try:
            return json.loads(repaired)
        except json.JSONDecodeError:
            return None

# --- demo ---
raw_output = """```json
{'name': 'Ada', 'score': 92}
```"""

result = parse_with_repair(raw_output)
print(result)  # {'name': 'Ada', 'score': 92}

# Layered output correction with Pydantic + optional LLM fallback
import json, re
from pydantic import BaseModel, ValidationError
import openai

client = openai.OpenAI()

class ProductReview(BaseModel):
    product_id: str
    sentiment: str   # "positive" | "negative" | "neutral"
    score: float     # 0.0–1.0
    summary: str

SCHEMA_JSON = ProductReview.model_json_schema()

def syntax_repair(raw: str) -> str:
    text = re.sub(r"```(?:json)?\s*", "", raw).replace("```", "").strip()
    text = re.sub(r"//[^\n]*", "", text)          # strip JS comments
    text = re.sub(r",\s*([}\]])", r"\1", text)  # trailing commas
    return text

def schema_repair(data: dict) -> dict:
    if "sentiment" in data:
        v = str(data["sentiment"]).lower().strip()
        data["sentiment"] = v if v in {"positive", "negative", "neutral"} else "neutral"
    if "score" in data:
        try:
            data["score"] = max(0.0, min(1.0, float(data["score"])))
        except (TypeError, ValueError):
            data["score"] = 0.5
    data.setdefault("product_id", "unknown")
    data.setdefault("summary", "")
    return data

def llm_fix(raw: str, error: str) -> str | None:
    prompt = (f"Fix this JSON to match the schema:\n{json.dumps(SCHEMA_JSON)}\n"
              f"Error: {error}\nBad output: {raw}\nReturn ONLY corrected JSON.")
    try:
        r = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[{"role": "user", "content": prompt}],
            temperature=0, max_tokens=300,
        )
        return r.choices[0].message.content
    except Exception:
        return None

def correct_output(raw: str, *, llm_fallback: bool = True) -> ProductReview | None:
    corrections: list[str] = []
    cleaned = syntax_repair(raw)
    try:
        data = json.loads(cleaned)
    except json.JSONDecodeError as e:
        corrections.append(f"syntax_error: {e}")
        if not llm_fallback:
            return None
        fixed = llm_fix(raw, str(e))
        if fixed is None:
            return None
        try:
            data = json.loads(syntax_repair(fixed))
        except json.JSONDecodeError:
            return None

    data = schema_repair(data)
    corrections.append("schema_repair")
    try:
        model = ProductReview(**data)
    except ValidationError as e:
        if not llm_fallback:
            return None
        fixed = llm_fix(raw, str(e))
        if fixed is None:
            return None
        try:
            data = schema_repair(json.loads(syntax_repair(fixed)))
            model = ProductReview(**data)
        except Exception:
            return None

    print(f"[audit] {corrections}")
    return model

# Demo
bad = """```json
{'product_id': 'P-123', "sentiment": "POSITIVE", "score": 1.4}
```"""
review = correct_output(bad, llm_fallback=False)
print(review.model_dump() if review else None)
# {'product_id': 'P-123', 'sentiment': 'positive', 'score': 1.0, 'summary': ''}

// JavaScript: streaming JSON repair with json-repair library (Node.js)
// npm install json-repair

import { jsonrepair } from "json-repair";
import Ajv from "ajv";  // npm install ajv

const ajv = new Ajv();

const reviewSchema = {
  type: "object",
  required: ["product_id", "sentiment", "score"],
  properties: {
    product_id: { type: "string" },
    sentiment: { type: "string", enum: ["positive", "negative", "neutral"] },
    score: { type: "number", minimum: 0, maximum: 1 },
    summary: { type: "string" },
  },
};

const validate = ajv.compile(reviewSchema);

/**
 * Attempt to repair and validate LLM JSON output.
 * Returns { data, repaired: boolean } or throws if unrecoverable.
 */
function correctOutput(raw) {
  // Layer 1: strip markdown fences
  let text = raw.replace(/```json?\s*/gi, "").replace(/```/g, "").trim();

  // Layer 2: use json-repair for deep syntax recovery
  let repaired = false;
  let data;
  try {
    data = JSON.parse(text);
  } catch {
    try {
      const fixed = jsonrepair(text);
      data = JSON.parse(fixed);
      repaired = true;
      console.warn("[audit] json-repair was applied");
    } catch (err) {
      throw new Error(`Unrecoverable JSON syntax: ${err.message}`);
    }
  }

  // Layer 3: schema coercion
  if (data.sentiment) {
    data.sentiment = String(data.sentiment).toLowerCase().trim();
  }
  if (typeof data.score === "number") {
    data.score = Math.max(0, Math.min(1, data.score));
  }
  data.summary ??= "";

  // Layer 4: AJV validation
  const valid = validate(data);
  if (!valid) {
    const errors = ajv.errorsText(validate.errors);
    throw new Error(`Schema validation failed after repair: ${errors}`);
  }

  return { data, repaired };
}

// Demo
const malformed = `\`\`\`json
{'product_id': "P-456", sentiment: POSITIVE, "score": 0.87}
\`\`\``;

try {
  const { data, repaired } = correctOutput(malformed);
  console.log("Corrected:", data, "| repaired:", repaired);
} catch (err) {
  console.error("Correction failed:", err.message);
}

# Async named-entity extraction pipeline with layered correction
import asyncio, json, re, logging
from collections import Counter
from pydantic import BaseModel, ValidationError

logger = logging.getLogger("output_corrector")

class ExtractedEntity(BaseModel):
    entity_type: str
    value: str
    confidence: float = 1.0
    metadata: dict = {}

    class Config:
        extra = "ignore"

counters: Counter = Counter()

async def correct_extraction(raw: str) -> list[ExtractedEntity]:
    counters["attempted"] += 1
    text = re.sub(r"```(?:json)?\s*", "", raw).replace("```", "").strip()
    text = re.sub(r",\s*([}\]])", r"\1", text)

    try:
        data = json.loads(text)
    except json.JSONDecodeError:
        counters["syntax_error"] += 1
        logger.warning("parse failed, skipping item")
        return []

    items = data if isinstance(data, list) else [data]
    results = []
    for item in items:
        if "confidence" in item:
            try:
                item["confidence"] = max(0.0, min(1.0, float(item["confidence"])))
            except (TypeError, ValueError):
                item["confidence"] = 1.0
                counters["confidence_clamped"] += 1
        try:
            results.append(ExtractedEntity(**item))
        except ValidationError:
            counters["schema_drop"] += 1

    counters["success"] += 1
    return results

if __name__ == "__main__":
    samples = [
        '[{"entity_type":"PERSON","value":"Ada Lovelace","confidence":0.95}]',
        '```json\n{"entity_type":"ORG","value":"Acme Corp","confidence":1.5}\n```',
        'this is not json at all',
    ]
    results = asyncio.run(asyncio.gather(*[correct_extraction(s) for s in samples]))
    for r in results:
        print([e.model_dump() for e in r])
    print("Counters:", dict(counters))
    # {'attempted': 3, 'confidence_clamped': 1, 'success': 2, 'syntax_error': 1}

# ── WRONG: silent fix without logging ────────────────────────────────────
def bad_correct(raw):
    try:
        return json.loads(raw)
    except Exception:
        # Silently return None — no log, no metric
        return None

# ── WRONG: fixing financial data heuristically ─────────────────────────
def bad_fix_amount(data):
    data["amount"] = data.get("amount", 0)   # silently replaces missing with 0
    return data

# ── CORRECT: log every correction, never silently coerce critical fields ─
import logging
logger = logging.getLogger(__name__)

def good_correct(raw: str, *, allow_repair: bool = True) -> dict | None:
    try:
        return json.loads(raw)
    except json.JSONDecodeError as exc:
        if not allow_repair:
            logger.error("JSON parse failed and repair disabled: %s", exc)
            return None
        # Attempt repair — but always log it
        repaired = raw.replace("'", "\"")
        try:
            data = json.loads(repaired)
            logger.warning("[audit] quote-repair applied to LLM output")
            return data
        except json.JSONDecodeError:
            logger.error("All repair attempts failed: %s", exc)
            return None

def good_fix_amount(data: dict, *, context: str) -> dict:
    if "amount" not in data:
        logger.error("[audit] Missing 'amount' field — escalating, not defaulting. context=%s", context)
        raise ValueError("Missing required financial field: amount")
    return data
